ONE_MODE_KAPPA_RANGE = (4.0, 8.0)
N_COMPONENTS = 4
MIXTURE_WEIGHTS = np.ones(N_COMPONENTS, dtype=np.float64) / N_COMPONENTS

SHAPE_CASES = ["same", "1_unique", "2_unique", "4_unique"]
MU_LAYOUTS = ["close", "spread", "symmetric"]

# Fast skewed spherical components. The mixture components are generated by
# skewed anisotropic tangent-plane perturbations followed by the S^2 exponential map.
# Thus every returned observation lies on S^2, but the components are not standard vMFs.
MIXTURE_KAPPA_RANGE = (6.0, 28.0)
MIXTURE_BETA_RANGE = (0.35, 1.35)
MIXTURE_SKEW_ABS_RANGE = (1.60, 3.20)
MIXTURE_SKEW_RANGE = (-MIXTURE_SKEW_ABS_RANGE[1], MIXTURE_SKEW_ABS_RANGE[1])
MIXTURE_ANGLE_RANGE = (0.0, np.pi)
MIN_UNIQUE_PARAM_DISTANCE = 0.75
MAX_PARAM_RESAMPLE_ATTEMPTS = 300

CLOSE_RADIUS_RANGE = (0.28, 0.62)
CLOSE_MIN_SEP = 0.10
SPREAD_MIN_SEP_RANGE = (0.85, 1.20)
SYMMETRIC_RADIUS_RANGE = (0.32, 0.85)
SYMMETRIC_RADIUS_JITTER = 0.12

BASELINE_SPECS = [
    {"kind": "uniform", "case": "uniform", "plot_group": "uniform", "shape_case": "baseline", "mu_layout": "baseline"},
    {"kind": "one_vmf", "case": "one_vmf", "plot_group": "one_vmf", "shape_case": "baseline", "mu_layout": "baseline"},
]

SHAPE_LABELS = {
    "uniform": "Uniform", "one_vmf": "1 vMF", "same": "Same",
    "1_unique": "1 unique", "2_unique": "2 unique", "4_unique": "4 unique",
}
MU_LABELS = {"close": "close centers", "spread": "spread centers", "symmetric": "symmetric centers"}
MU_MARKERS = {"close": "o", "spread": "s", "symmetric": "^"}
MU_COLORS = {"close": get_single_color(2), "spread": get_single_color(5), "symmetric": get_single_color(8)}
X_POS = {"uniform": 0.0, "one_vmf": 1.8, "same": 4.0, "1_unique": 5.6, "2_unique": 7.2, "4_unique": 8.8}
LAYOUT_X_OFFSET = {"close": -0.28, "spread": 0.0, "symmetric": 0.28}

LDD_REPRESENTATION_METRICS = [
    ("ldd_variance_source", "LDD variance"),
    ("ldd_effective_rank_source", "LDD effective rank"),
    ("ldd_spectral_entropy_source", "LDD spectral entropy"),
]
ROW_COUPLING_METRICS = [
    ("coupling_row_nonuniformity", "Coupling row non-uniformity"),
    ("coupling_row_peak_ratio_mean", "Coupling row peak ratio"),
]
